View.renderCameraTabs = (ws) => {
  const strip = document.getElementById('camTabs');
  const tabs = [...ws.cameras.map(c => ({ id: c.id, label: c.name }))];
  if ((ws.polygonsByCamera.default || []).length) tabs.unshift({ id: 'default', label: 'default' });
  strip.style.display = tabs.length > 1 || ws.cameras.length ? 'flex' : 'none';
  strip.innerHTML = tabs.map(t =>
    `<button class="cam-tab ${t.id === ws.activeCameraId ? 'active' : ''}" data-cam="${t.id}">${t.label}</button>`
  ).join('') + '<button class="cam-tab add" data-cam="__add">+ Camera</button>';
};
document.getElementById('camTabs').addEventListener('click', e => {
  const id = e.target.dataset.cam;
  if (!id) return;
  id === '__add' ? switchTab('cameras', document.querySelector('.tab:nth-child(2)')) : Store.setActiveCamera(id);
});

Yaml.generate = (ws, scope) => scope === 'all'
  ? Yaml.fullConfig(ws)            // cameras: { name: { ffmpeg, detect, zones, motion, objects } }
  : Yaml.cameraSnippet(ws, ws.activeCameraId); // zones/motion/objects only
